import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { Search, Sun, Cloud, CloudRain, Wind, Droplets, Thermometer, CloudLightning, CloudSnow, Disc, Music, Layers } from 'lucide-react';
import './App.css';

const API_KEY = "1d30e0668b384c4d133dc45fe617b03b"; 

function App() {
  const [city, setCity] = useState('Visnagar');
  const [weatherData, setWeatherData] = useState(null);
  const [forecastData, setForecastData] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const fetchWeather = async (searchCity) => {
    setLoading(true);
    setError('');
    try {
      const currentRes = await axios.get(
        `https://api.openweathermap.org/data/2.5/weather?q=${searchCity}&units=metric&appid=${API_KEY}`
      );
      setWeatherData(currentRes.data);

      const forecastRes = await axios.get(
        `https://api.openweathermap.org/data/2.5/forecast?q=${searchCity}&units=metric&appid=${API_KEY}`
      );

      const dailyData = forecastRes.data.list.filter(item => item.dt_txt.includes("12:00:00"));
      setForecastData(dailyData);

    } catch (err) {
      setError('સિટી મળ્યું નથી, દોસ્ત!');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchWeather(city);
  }, []);

  const handleSearch = (e) => {
    e.preventDefault();
    if (city.trim()) fetchWeather(city);
  };

  const getWeatherIcon = (main, size = 32) => {
    switch (main) {
      case 'Clear': return <Sun className="lofi-glow text-amber" size={size} />;
      case 'Clouds': return <Cloud className="lofi-glow text-slate" size={size} />;
      case 'Rain': case 'Drizzle': return <CloudRain className="lofi-glow text-cyan" size={size} />;
      case 'Thunderstorm': return <CloudLightning className="lofi-glow text-purple" size={size} />;
      case 'Snow': return <CloudSnow className="lofi-glow text-blue" size={size} />;
      default: return <Sun className="lofi-glow text-amber" size={size} />;
    }
  };

  return (
    <div className="lofi-station-app">
      {/* Cinematic Aura Background Backdrops */}
      <div className="bg-glow-orb-1"></div>
      <div className="bg-glow-orb-2"></div>

      <div className="lofi-player-card">

        {/* Minimal Player Header */}
        <header className="player-header">
          <div className="station-identity">
            <Disc className="vinyl-animation text-cyan" size={20} />
            <h2>Atmosphere<span>.fm</span></h2>
          </div>

          <form onSubmit={handleSearch} className="lofi-search-input">
            <input 
              type="text" 
              placeholder="Track City..." 
              value={city}
              onChange={(e) => setCity(e.target.value)}
            />
            <button type="submit"><Search size={14} /></button>
          </form>
        </header>

        {loading && <div className="station-status">Buffering live atmosphere...</div>}
        {error && <div className="station-status error">{error}</div>}

        {weatherData && !loading && !error && (
          <div className="player-tracklist-view">

            {/* CURRENT TRACK: HERO DISPLAY */}
            <div className="current-track-banner">
              <div className="track-album-art">
                {getWeatherIcon(weatherData.weather[0].main, 80)}
              </div>
              <div className="track-metadata">
                <span className="now-playing-tag">NOW PLAYING</span>
                <h1 className="track-city-title">{weatherData.name}</h1>
                <p className="track-artist-sub">{weatherData.weather[0].description.toUpperCase()}</p>
              </div>
              <div className="track-main-metric">
                <h2>{Math.round(weatherData.main.temp)}°C</h2>
              </div>
            </div>

            {/* QUICK STATS METRICS (Looks like Mixer Controls) */}
            <div className="mixer-analytics-grid">
              <div className="mixer-fader-card">
                <div className="fader-label"><Thermometer size={14} /> <span>Feels Like</span></div>
                <h3>{Math.round(weatherData.main.feels_like)}°C</h3>
              </div>
              <div className="mixer-fader-card">
                <div className="fader-label"><Droplets size={14} /> <span>Humidity</span></div>
                <h3>{weatherData.main.humidity}%</h3>
              </div>
              <div className="mixer-fader-card">
                <div className="fader-label"><Wind size={14} /> <span>Wind Speed</span></div>
                <h3>{weatherData.wind.speed} <small>m/s</small></h3>
              </div>
            </div>

            {/* UPCOMING FORECAST: AS A MUSIC TRACKLIST */}
            <div className="lofi-tracklist-section">
              <h3><Music size={14} /> Upcoming Forecast Tracks</h3>
              <div className="track-rows-container">
                {forecastData.map((day, idx) => (
                  <div key={idx} className="track-row">
                    <span className="track-index">0{idx + 1}</span>
                    <span className="track-name">
                      {new Date(day.dt * 1000).toLocaleDateString('gu-IN', { weekday: 'long' })}
                    </span>
                    <div className="track-vibe-icon-group">
                      {getWeatherIcon(day.weather[0].main, 18)}
                      <span className="track-genre">{day.weather[0].main}</span>
                    </div>
                    <span className="track-duration">{Math.round(day.main.temp)}°C</span>
                  </div>
                ))}
              </div>
            </div>

          </div>
        )}
      </div>
    </div>
  );
}

export default App;
